'use client';

import { User, Settings, Bookmark, Bell, Shield, LogOut, Heart } from 'lucide-react';
import { mockProducts, mockUserProfile } from '@/data/mockData';
import { DecisionBadge } from '@/components/ui/DecisionBadge';
import { useWishlistStore } from '@/store/wishlistStore';

export default function ProfilePage() {
  const { username, memberSince, stats, favoriteSeries } = mockUserProfile;
  const { wishlist, toggle } = useWishlistStore();

  // wishlist id 배열 → 실제 Product 객체
  const wishedProducts = mockProducts.filter((p) => wishlist.includes(p.id));

  const prefItems = [
    { icon: Bell,     label: '알림 설정' },
    { icon: Shield,   label: '개인정보 & 보안' },
    { icon: Settings, label: '앱 설정' },
  ];

  return (
    <div className="p-6 lg:p-10 max-w-5xl mx-auto w-full">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-white mb-2">프로필</h1>
        <p className="text-zinc-400">선호 설정과 저장된 인사이트를 관리하세요.</p>
      </div>

      <div className="grid lg:grid-cols-[1fr_300px] gap-8">
        {/* 메인 콘텐츠 */}
        <div className="space-y-8">
          {/* 프로필 헤더 */}
          <div className="bg-surface border border-surface-border rounded-xl p-6 flex items-center gap-6">
            <div className="w-20 h-20 rounded-full bg-surface-raised border border-surface-border-light flex items-center justify-center">
              <User className="w-8 h-8 text-zinc-500" />
            </div>
            <div>
              <h2 className="text-2xl font-bold text-white mb-1">{username}</h2>
              <p className="text-sm text-zinc-400 mb-3">{memberSince}년부터 회원</p>
              <div className="flex gap-4 text-sm">
                <span className="text-zinc-300">
                  <strong className="text-white">{stats.decisionsSaved}</strong> 저장
                </span>
                <span className="text-zinc-300">
                  <strong className="text-white">{wishedProducts.length}</strong> 관심
                </span>
              </div>
            </div>
            <button className="ml-auto px-4 py-2 bg-surface-raised hover:bg-surface-overlay border border-surface-border rounded-lg text-sm font-medium text-white transition-colors">
              프로필 편집
            </button>
          </div>

          {/* 관심 시리즈 */}
          <div className="bg-surface border border-surface-border rounded-xl p-6">
            <h3 className="text-lg font-semibold text-white mb-4">관심 시리즈</h3>
            <div className="flex flex-wrap gap-2">
              {favoriteSeries.map((series) => (
                <span
                  key={series}
                  className="px-3 py-1.5 bg-surface-raised border border-surface-border-light rounded-lg text-sm text-zinc-300"
                >
                  {series}
                </span>
              ))}
              <button className="px-3 py-1.5 border border-dashed border-surface-border rounded-lg text-sm text-zinc-500 hover:text-white hover:border-zinc-500 transition-colors">
                + 추가
              </button>
            </div>
          </div>

          {/* 찜 목록 */}
          <div className="bg-surface border border-surface-border rounded-xl p-6">
            <h3 className="text-lg font-semibold text-white mb-6 flex items-center gap-2">
              <Bookmark className="w-5 h-5 text-brand-500" /> 관심 목록
              <span className="text-sm font-normal text-zinc-500">({wishedProducts.length})</span>
            </h3>

            {wishedProducts.length > 0 ? (
              <div className="space-y-3">
                {wishedProducts.map((item) => (
                  <div
                    key={item.id}
                    className="flex items-center justify-between p-4 bg-surface-base border border-surface-border rounded-lg hover:border-surface-border-light transition-colors"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-surface-raised rounded flex items-center justify-center border border-surface-border">
                        <div className="w-6 h-6 text-zinc-600" />
                      </div>
                      <div>
                        <div className="font-medium text-white">{item.name}</div>
                        <div className="text-xs text-zinc-400">{item.grade}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <div className="text-right hidden sm:block">
                        <div className="font-bold text-white">${item.price.toFixed(2)}</div>
                      </div>
                      <DecisionBadge decision={item.decision} size="sm" />
                      <button
                        onClick={() => toggle(item.id)}
                        className="p-1.5 rounded-full text-brand-400 hover:bg-brand-500/10 transition-colors"
                        aria-label="찜 해제"
                      >
                        <Heart className="w-4 h-4 fill-current" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-10 border border-dashed border-surface-border rounded-xl">
                <Heart className="w-8 h-8 text-zinc-700 mx-auto mb-3" />
                <p className="text-sm text-zinc-500">찜한 키트가 없습니다.</p>
                <p className="text-xs text-zinc-600 mt-1">피드에서 하트를 눌러보세요.</p>
              </div>
            )}
          </div>
        </div>

        {/* 사이드 설정 */}
        <div className="space-y-6">
          <div className="bg-surface border border-surface-border rounded-xl p-6">
            <h3 className="text-sm font-semibold text-white mb-4 uppercase tracking-wider">환경설정</h3>
            <div className="space-y-1">
              {prefItems.map((item, i) => (
                <button
                  key={i}
                  className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium text-zinc-400 hover:text-white hover:bg-surface-raised transition-colors"
                >
                  <item.icon className="w-4 h-4" />
                  {item.label}
                </button>
              ))}
            </div>
            <div className="mt-8 pt-6 border-t border-surface-border">
              <button className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium text-brand-500 hover:bg-brand-500/10 transition-colors">
                <LogOut className="w-4 h-4" />
                로그아웃
              </button>
            </div>
          </div>

          <div className="bg-brand-500/10 border border-brand-500/20 rounded-xl p-5 text-center">
            <div className="text-2xl font-bold text-white mb-1">
              ${stats.moneySaved.toFixed(2)}
            </div>
            <div className="text-xs text-brand-400 uppercase tracking-wider font-medium">예상 절약 금액</div>
            <p className="text-xs text-zinc-400 mt-2">기다리기 결정을 따른 결과 기준</p>
          </div>
        </div>
      </div>
    </div>
  );
}
